@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Tasks="allTasks" />
    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        <BoardColumn ColumnName="To Do"
                     Tasks="GetFilteredTasks("To Do")"
                     ShowMoveLeft="false"
                     ShowMoveRight="true"
                     OnMoveRight="task => MoveTask(task, "In Progress")"
                     OnTaskCreated="HandleTaskCreated" />

        <BoardColumn ColumnName="In Progress"
                     Tasks="GetFilteredTasks("In Progress")"
                     ShowMoveLeft="true"
                     ShowMoveRight="true"
                     OnMoveLeft="task => MoveTask(task, "To Do")"
                     OnMoveRight="task => MoveTask(task, "Done")"
                     OnTaskCreated="HandleTaskCreated" />

        <BoardColumn ColumnName="Done"
                     Tasks="GetFilteredTasks("Done")"
                     ShowMoveLeft="true"
                     ShowMoveRight="false"
                     OnMoveLeft="task => MoveTask(task, "In Progress")"
                     OnTaskCreated="HandleTaskCreated" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = string.Empty;
    private bool loading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        try
        {
            loading = true;
            errorMessage = null;
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private void HandleSearchChanged(string value)
    {
        searchText = value;
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return tasks.ToList();
    }

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = allTasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                allTasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleTaskCreated((string Title, string Assignee, string Priority, DateTime DueDate, string Status) data)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
            allTasks.Add(newTask with { Status = data.Status });
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

